import numpy as np

def exact_qft_matrix(n):
    """Create exact QFT matrix."""
    N = 2**n
    omega = np.exp(2j * np.pi / N)
    return np.array([[omega**(j*k) for k in range(N)] 
                     for j in range(N)]) / np.sqrt(N)

def approx_qft_matrix(n, m):
    """
    Create approximate QFT matrix with cutoff m.
    """
    N = 2**n
    result = np.zeros((N, N), dtype=complex)

    for j in range(N):
        for k in range(N):
            # Compute phase using only first m bits of precision
            # Phase = j*k/N, but we truncate the binary expansion
            phase = 0
            for b in range(min(m, n)):
                if (k >> b) & 1:
                    phase += j / (2**(b + 1))
            result[j, k] = np.exp(2j * np.pi * phase)

    return result / np.sqrt(N)

def measure_error(exact, approx):
    """Measure relative error (Frobenius norm)."""
    return np.linalg.norm(exact - approx) / np.linalg.norm(exact)

for n in [3, 4, 5]:
    exact = exact_qft_matrix(n)
    print(f"\nn = {n} qubits:")
    for m in range(1, n + 1):
        approx = approx_qft_matrix(n, m)
        error = measure_error(exact, approx)
        status = "(exact)" if error < 1e-10 else ""
        print(f"  m = {m}: error = {error:.6f} {status}")
